mapper.delete:
DELETE FROM interaction
WHERE user_id = #{userId}
  AND product_id = #{productId}
  AND action_type = #{actionType}

mapper.select:
SELECT * FROM interaction
WHERE user_id = #{userId}
  AND product_id = #{productId}
  AND action_type = #{actionType}
LIMIT 1

SELECT i.id, i.user_id AS userId, i.product_id AS productId, i.action_type AS actionType,
       i.action_time AS actionTime,
       p.name AS productName, p.cover_list AS coverList, p.price AS productPrice
FROM interaction i
LEFT JOIN product p ON i.product_id = p.id
WHERE i.user_id = #{userId}
  AND i.action_type = #{actionType}
ORDER BY i.action_time DESC

    LIMIT #{current},#{size}

SELECT COUNT(*)
FROM interaction i
WHERE i.user_id = #{userId}
  AND i.action_type = #{actionType}
